// Normalize incoming form submission into standard review format
const item = $input.first().json;
return [{
  json: {
    source: 'form_submission',
    product_name: String(item['Product Name'] || 'Unknown Product').trim(),
    review_text: String(item['Review Text'] || '').trim(),
    rating: Math.min(5, Math.max(1, parseFloat(item['Star Rating (1-5)']) || 3)),
    reviewer_name: String(item['Reviewer Name'] || 'Anonymous').trim(),
    review_date: new Date().toISOString().split('T')[0],
    review_id: 'FORM-' + Date.now()
  }
}];

// Mock database fetch – replace with real HTTP or DB node
const today = new Date().toISOString().split('T')[0];
const reviews = [
  {
    source: 'scheduled_db_fetch',
    product_name: 'UltraSound Bluetooth Speaker 360',
    review_text: 'Outstanding sound quality for its compact size. The 360-degree audio fills any room. The waterproof design genuinely works — survived a pool party. Battery easily lasts 20 hours. I have recommended this to 4 friends already and all of them love it too.',
    rating: 5,
    reviewer_name: 'AudioPhile_James',
    review_date: today,
    review_id: 'DB-' + Date.now() + '-001'
  },
  {
    source: 'scheduled_db_fetch',
    product_name: 'RiseUp Standing Desk Converter',
    review_text: 'The desk itself works well and the height adjustment range is good. But delivery took 3 weeks instead of the promised 3-5 days with zero communication. Packaging was visibly damaged on arrival and one piece had a visible scratch. Product quality is fine but the fulfillment process is a serious problem.',
    rating: 2.5,
    reviewer_name: 'ProductivityGuru_Sam',
    review_date: today,
    review_id: 'DB-' + Date.now() + '-002'
  }
];
return reviews.map(r => ({ json: r }));

// Validate and sanitize all incoming reviews before sending to AI
const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No reviews received for processing. Check trigger configuration.');
}

const validated = [];
const skipped = [];

for (const item of items) {
  const r = item.json;
  if (!r.review_text || r.review_text.trim().length < 15) {
    skipped.push({ id: r.review_id || 'unknown', reason: 'Review text missing or too short (< 15 chars)' });
    continue;
  }
  if (!r.product_name || r.product_name.trim().length < 2) {
    skipped.push({ id: r.review_id || 'unknown', reason: 'Product name missing' });
    continue;
  }
  validated.push({
    json: {
      source: r.source || 'unknown',
      product_name: r.product_name.trim().substring(0, 200),
      review_text: r.review_text.trim().substring(0, 3000),
      rating: Math.min(5, Math.max(1, parseFloat(r.rating) || 3)),
      reviewer_name: (r.reviewer_name || 'Anonymous').trim().substring(0, 100),
      review_date: r.review_date || new Date().toISOString().split('T')[0],
      review_id: r.review_id || ('GEN-' + Date.now() + '-' + Math.random().toString(36).substring(2, 8).toUpperCase()),
      ingested_at: new Date().toISOString()
    }
  });
}

if (skipped.length > 0) console.warn('[Validation] Skipped:', JSON.stringify(skipped));
if (validated.length === 0) throw new Error('All reviews failed validation: ' + JSON.stringify(skipped));

console.log(`[Validation] ✅ ${validated.length} valid | ⏭️ ${skipped.length} skipped`);
return validated;

