// Parse NVIDIA's response (OpenAI-compatible format) and merge with original review
const apiResponse = $input.first().json;
let originalReview;
try {
  originalReview = $('✅ Validate & Sanitize').item.json;
} catch (e) {
  originalReview = {};
}

try {
  if (apiResponse.error) {
    throw new Error(`API Error: ${apiResponse.error.message || JSON.stringify(apiResponse.error)}`);
  }
  const content = apiResponse.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content in API response');

  let rawText = content.trim();
  rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  const analysis = JSON.parse(rawText);

  if (!analysis.sentiment) throw new Error('Missing required field: sentiment');

  return [{
    json: {
      review_id: originalReview.review_id || 'UNKNOWN',
      source: originalReview.source || 'unknown',
      product_name: originalReview.product_name || 'Unknown Product',
      rating: originalReview.rating || 3,
      reviewer_name: originalReview.reviewer_name || 'Anonymous',
      review_date: originalReview.review_date || '',
      review_text: originalReview.review_text || '',
      ingested_at: originalReview.ingested_at || '',
      sentiment: analysis.sentiment,
      sentiment_score: Number(analysis.sentiment_score) || 5,
      confidence: Number(analysis.confidence) || 70,
      key_topics: Array.isArray(analysis.key_topics) ? analysis.key_topics.join(' | ') : String(analysis.key_topics || ''),
      main_praise: analysis.main_praise || null,
      main_issue: analysis.main_issue || null,
      ai_summary: analysis.summary || '',
      priority: analysis.priority || 'medium',
      priority_reason: analysis.priority_reason || '',
      suggested_response: analysis.suggested_response || '',
      product_insight: analysis.product_insight || '',
      tags: Array.isArray(analysis.tags) ? analysis.tags.join(' | ') : String(analysis.tags || ''),
      analysis_status: 'success',
      analyzed_at: new Date().toISOString(),
      model_used: apiResponse.model || 'llama3-70b-instruct',
      input_tokens: apiResponse.usage?.prompt_tokens || 0,
      output_tokens: apiResponse.usage?.completion_tokens || 0
    }
  }];
} catch (err) {
  console.error('[ParseError]', err.message);
  return [{
    json: {
      review_id: originalReview?.review_id || 'PARSE-ERR',
      product_name: originalReview?.product_name || 'Unknown',
      source: originalReview?.source || 'unknown',
      rating: originalReview?.rating || null,
      review_text: originalReview?.review_text || '',
      analysis_status: 'error',
      error_message: err.message,
      analyzed_at: new Date().toISOString()
    }
  }];
}

// Enrich successful analyses with business metrics
const r = $input.first().json;
if (r.analysis_status === 'error') return [{ json: r }];

const nps_category = r.rating >= 4.5 ? 'promoter' : r.rating >= 3.5 ? 'passive' : 'detractor';
let urgency_level;
const isNegative = r.sentiment === 'negative';
const isCriticalRating = r.rating <= 2;
const isHighPriority = r.priority === 'high';
if ((isNegative && isCriticalRating) || (isHighPriority && isCriticalRating)) urgency_level = 'critical';
else if (isNegative || isHighPriority || isCriticalRating) urgency_level = 'urgent';
else if (r.priority === 'medium' || r.rating <= 3.5) urgency_level = 'monitor';
else urgency_level = 'positive';

const actions = [];
if (['critical', 'urgent'].includes(urgency_level)) actions.push('📧 RESPOND: Use suggested_response within 24hrs');
if (r.main_issue) actions.push('🔨 PRODUCT: Investigate — ' + r.main_issue);
if (r.main_praise && r.rating >= 4) actions.push('📣 MARKETING: Highlight — ' + r.main_praise);
if (r.product_insight) actions.push('💡 TEAM: ' + r.product_insight);

const alignment = (
  (r.rating >= 4 && r.sentiment === 'positive') ||
  (r.rating <= 2 && r.sentiment === 'negative') ||
  (r.rating > 2 && r.rating < 4 && r.sentiment === 'neutral')
) ? 'aligned' : 'misaligned';

const stars = '★'.repeat(Math.round(r.rating)) + '☆'.repeat(5 - Math.round(r.rating));

return [{
  json: {
    ...r,
    nps_category,
    urgency_level,
    requires_response: ['critical', 'urgent'].includes(urgency_level),
    action_items: actions.join(' || '),
    rating_vs_sentiment: alignment,
    star_display: stars,
    processing_complete: true
  }
}];

// Aggregate all processed reviews into a comprehensive analytics report
const items = $input.all();
const allReviews = items.map(i => i.json);
const successful = allReviews.filter(r => r.analysis_status === 'success' && r.processing_complete);
const failed = allReviews.filter(r => r.analysis_status !== 'success');
const total = allReviews.length;
const n = successful.length;

if (n === 0) {
  return [{ json: { error: 'No reviews successfully analyzed', processing_summary: { total_received: total, successfully_analyzed: 0, failed: failed.length } } }];
}

const avgRating = successful.reduce((s, r) => s + r.rating, 0) / n;
const avgSentimentScore = successful.reduce((s, r) => s + r.sentiment_score, 0) / n;
const totalTokens = successful.reduce((s, r) => s + (r.input_tokens || 0) + (r.output_tokens || 0), 0);
const sentimentCount = { positive: 0, neutral: 0, negative: 0 };
const urgencyCount = { critical: 0, urgent: 0, monitor: 0, positive: 0 };
const npsCount = { promoter: 0, passive: 0, detractor: 0 };
const priorityCount = { high: 0, medium: 0, low: 0 };

successful.forEach(r => {
  sentimentCount[r.sentiment] = (sentimentCount[r.sentiment] || 0) + 1;
  urgencyCount[r.urgency_level] = (urgencyCount[r.urgency_level] || 0) + 1;
  npsCount[r.nps_category] = (npsCount[r.nps_category] || 0) + 1;
  priorityCount[r.priority] = (priorityCount[r.priority] || 0) + 1;
});

const npsScore = Math.round(((npsCount.promoter - npsCount.detractor) / n) * 100);
const sentimentHealthScore = Math.round(avgSentimentScore * 10);

const allTopics = successful.flatMap(r => r.key_topics ? r.key_topics.split(' | ').map(t => t.trim()) : []).filter(Boolean);
const topicFreq = {};
allTopics.forEach(t => { topicFreq[t] = (topicFreq[t] || 0) + 1; });
const topTopics = Object.entries(topicFreq).sort((a, b) => b[1] - a[1]).slice(0, 8).map(([t, c]) => `${t} (${c}x)`);

const allTags = successful.flatMap(r => r.tags ? r.tags.split(' | ').map(t => t.trim()) : []).filter(Boolean);
const tagFreq = {};
allTags.forEach(t => { tagFreq[t] = (tagFreq[t] || 0) + 1; });
const topTags = Object.entries(tagFreq).sort((a, b) => b[1] - a[1]).slice(0, 6).map(([t, c]) => `${t}(${c})`);

const needResponse = successful.filter(r => r.requires_response);
const topIssues = successful.filter(r => r.main_issue).map(r => r.main_issue).slice(0, 3);
const topPraises = successful.filter(r => r.main_praise).map(r => r.main_praise).slice(0, 3);
const insights = successful.filter(r => r.product_insight).map(r => ({ product: r.product_name, insight: r.product_insight }));

const recommendations = [];
if (avgRating < 3.5) recommendations.push('🔴 CRITICAL: Average rating below 3.5 — immediate product/service review required');
if (sentimentCount.negative > n * 0.4) recommendations.push('🔴 CRITICAL: Over 40% negative sentiment — investigate root causes urgently');
if (npsCount.detractor > n * 0.3) recommendations.push('🟡 WARNING: More than 30% detractors — customer retention programs needed');
if (urgencyCount.critical > 0) recommendations.push(`🔴 ${urgencyCount.critical} CRITICAL review(s) — respond within 4 hours`);
if (urgencyCount.urgent > 0) recommendations.push(`🟡 ${urgencyCount.urgent} URGENT review(s) — respond within 24 hours`);
if (npsCount.promoter > n * 0.5) recommendations.push('🟢 OPPORTUNITY: Over 50% promoters — activate referral and testimonial programs');
if (recommendations.length === 0) recommendations.push('✅ All metrics within healthy ranges — maintain current service quality');

const report = {
  report_id: 'RPT-' + new Date().toISOString().replace(/[^0-9]/g, '').substring(0, 14),
  generated_at: new Date().toISOString(),
  period: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
  processing_summary: { total_received: total, successfully_analyzed: n, failed: failed.length, success_rate: Math.round((n / total) * 100) + '%', total_ai_tokens_used: totalTokens },
  health_scores: { average_star_rating: Math.round(avgRating * 100) / 100, sentiment_health_score: sentimentHealthScore + '/100', nps_score: npsScore, response_required_count: needResponse.length },
  breakdowns: { by_sentiment: sentimentCount, by_urgency: urgencyCount, by_nps: npsCount, by_ai_priority: priorityCount },
  top_topics: topTopics.join(', '),
  top_tags: topTags.join(', '),
  top_issues_reported: topIssues,
  top_praises_reported: topPraises,
  recommendations,
  product_insights: insights,
  reviews_requiring_response: needResponse.map(r => ({ review_id: r.review_id, product: r.product_name, rating: r.rating, stars: r.star_display, urgency: r.urgency_level, sentiment: r.sentiment, issue: r.main_issue, suggested_response: r.suggested_response })),
  all_reviews: successful.map(r => ({ review_id: r.review_id, product: r.product_name, rating: r.rating, stars: r.star_display, sentiment: r.sentiment, sentiment_score: r.sentiment_score, priority: r.priority, urgency: r.urgency_level, nps_category: r.nps_category, key_topics: r.key_topics, summary: r.ai_summary, requires_response: r.requires_response })),
  failed_reviews: failed.map(r => ({ review_id: r.review_id, error: r.error_message }))
};

console.log('\n' + '═'.repeat(60));
console.log('📊 AI REVIEW ANALYSIS REPORT');
console.log('═'.repeat(60));
console.log(JSON.stringify(report, null, 2));
console.log('═'.repeat(60) + '\n');

return [{ json: report }];

// Final output with downstream integration hooks
const report = $input.first().json;
console.log('\n🎉 Pipeline Complete!');
console.log(`   📦 Total Reviews  : ${report.processing_summary?.total_received}`);
console.log(`   ✅ Success Rate   : ${report.processing_summary?.success_rate}`);
console.log(`   ⭐ Avg Rating     : ${report.health_scores?.average_star_rating}/5`);
console.log(`   💯 NPS Score      : ${report.health_scores?.nps_score}`);
console.log(`   🔔 Needs Response : ${report.health_scores?.response_required_count}`);
console.log(`   🎫 AI Tokens Used : ${report.processing_summary?.total_ai_tokens_used}`);
if (report.recommendations?.length > 0) {
  console.log('\n📋 Recommendations:');
  report.recommendations.forEach(r => console.log('   ' + r));
}
return [{ json: { ...report, pipeline_status: 'completed', completed_at: new Date().toISOString() } }];
